import "../../helpers/IToken.sol";



contract ExchangeService {
    using SafeMath for uint256;


    address public admin;


    uint256 public systemETH;


    uint256 public commission;


    uint256 public divider = 100000;


    uint256 public minEther;

    ISettings public settings;



    Ask[] public asks;



    struct Ask {
        address owner;
        uint256 pack;
    }


    event AskCreated(uint256 id, address owner, uint256 pack);


    event AskClosed(uint256 id, address who);


    event AskMatched(uint256 id, uint256 tBox, address who, address owner);

    event ExchangeFeeUpdated(uint256 _value);
    event ExchangeMinEtherUpdated(uint256 _value);


    modifier onlyAdmin() {
        require(admin == msg.sender, "You have no access");
        _;
    }


    modifier onlyOwner(uint256 _id) {
        require(asks[_id].owner == msg.sender, "Ask isn't your");
        _;
    }

    modifier onlyExists(uint256 _id) {
        require(asks[_id].owner != address(0), "Ask doesn't exist");
        _;
    }





    constructor(ISettings _settings) public {
        admin = msg.sender;
        settings = ISettings(_settings);

        commission = 500; 
        emit ExchangeFeeUpdated(commission);

        minEther = 1 ether;
        emit ExchangeMinEtherUpdated(minEther);
    }


    function withdrawSystemETH(address payable _beneficiary) external onlyAdmin {
        require(_beneficiary != address(0), "Zero address, be careful");
        require(systemETH > 0, "There is no available ETH");

        uint256 _systemETH = systemETH;
        systemETH = 0;
        _beneficiary.transfer(_systemETH);
    }


    function reclaimERC20(address _token, address _beneficiary) external onlyAdmin {
        require(_beneficiary != address(0), "Zero address, be careful");

        uint256 _amount = IToken(_token).balanceOf(address(this));
        require(_amount > 0, "There are no tokens");
        IToken(_token).transfer(_beneficiary, _amount);
    }


    function setCommission(uint256 _value) external onlyAdmin {
        require(_value <= 10000, "Too much");
        commission = _value;
        emit ExchangeFeeUpdated(_value);
    }


    function setMinEther(uint256 _value) external onlyAdmin {
        require(_value <= 100 ether, "Too much");
        minEther = _value;
        emit ExchangeMinEtherUpdated(_value);
    }


    function changeAdmin(address _newAdmin) external onlyAdmin {
        require(_newAdmin != address(0), "Zero address, be careful");
        admin = _newAdmin;
    }


    function create() public payable returns (uint256) {
        require(msg.value >= minEther, "Too small funds");

        Ask memory _ask = Ask(
            tx.origin,
            msg.value
        );
        uint256 _id = asks.push(_ask).sub(1);
        emit AskCreated(_id, tx.origin, msg.value);
        return _id;
    }


    function close(uint256 _id) external onlyOwner(_id) {

        uint256 _eth = asks[_id].pack;
        delete asks[_id];
        msg.sender.transfer(_eth);
        emit AskClosed(_id, msg.sender);
    }


    function take(uint256 _id) external payable onlyExists(_id) returns(uint256) {

        address _owner = asks[_id].owner;
        uint256 _eth = asks[_id].pack;
        uint256 _sysEth = _eth.mul(commission).div(divider);
        systemETH = systemETH.add(_sysEth);
        uint256 _tmv = _eth.mul(ILogic(settings.logicManager()).rate()).div(ILogic(settings.logicManager()).precision());
        uint256 _box = ILogic(settings.logicManager()).create.value(msg.value)(_tmv);
        uint256 _sysTmv = _tmv.mul(commission).div(divider);
        delete asks[_id];
        msg.sender.transfer(_eth.sub(_sysEth));
        ILogic(settings.logicManager()).transferFrom(address(this), msg.sender, _box);
        IToken(settings.tmvAddress()).transfer(_owner, _tmv.sub(_sysTmv));
        emit AskMatched(_id, _box, msg.sender, _owner);
        return _tmv.sub(_sysTmv);
    }
}

pragma solidity 0.5.11;

import "../../helpers/SafeMath.sol";
import "../../helpers/ISettings.sol";
import "../../helpers/IToken.sol";
import "../../helpers/ILogic.sol";



contract LeverageService {
    using SafeMath for uint256;


    address public admin;


    uint256 public systemETH;


    uint256 public commission;


    uint256 public divider = 100000;


    uint256 public minEther;

    ISettings public settings;



    Bid[] public bids;



    struct Bid {
        address payable owner;
        uint256         pack;
        uint256         percent;
    }


    event BidCreated(uint256 id, address owner, uint256 pack, uint256 percent);


    event BidClosed(uint256 id, address who);


    event BidMatched(uint256 id, uint256 tBox, address who, address owner);

    event LeverageFeeUpdated(uint256 _value);
    event LeverageMinEtherUpdated(uint256 _value);


    modifier onlyAdmin() {
        require(admin == msg.sender, "You have no access");
        _;
    }


    modifier onlyOwner(uint256 _id) {
        require(bids[_id].owner == msg.sender, "Bid isn't your");
        _;
    }

    modifier onlyExists(uint256 _id) {
        require(bids[_id].owner != address(0), "Bid doesn't exist");
        _;
    }





    constructor(ISettings _settings) public {
        admin = msg.sender;
        settings = ISettings(_settings);

        commission = 500; 
        emit LeverageFeeUpdated(commission);

        minEther = 1 ether;
        emit LeverageMinEtherUpdated(minEther);
    }


    function withdrawSystemETH(address payable _beneficiary) external onlyAdmin {
        require(_beneficiary != address(0), "Zero address, be careful");
        require(systemETH > 0, "There is no available ETH");

        uint256 _systemETH = systemETH;
        systemETH = 0;
        _beneficiary.transfer(_systemETH);
    }


    function reclaimERC20(address _token, address _beneficiary) external onlyAdmin {
        require(_beneficiary != address(0), "Zero address, be careful");

        uint256 _amount = IToken(_token).balanceOf(address(this));
        require(_amount > 0, "There are no tokens");
        IToken(_token).transfer(_beneficiary, _amount);
    }


    function setCommission(uint256 _value) external onlyAdmin {
        require(_value <= 10000, "Too much");
        commission = _value;
        emit LeverageFeeUpdated(_value);
    }


    function setMinEther(uint256 _value) external onlyAdmin {
        require(_value <= 100 ether, "Too much");
        minEther = _value;
        emit LeverageMinEtherUpdated(_value);
    }


    function changeAdmin(address _newAdmin) external onlyAdmin {
        require(_newAdmin != address(0), "Zero address, be careful");
        admin = _newAdmin;
    }


    function create(uint256 _percent) public payable returns (uint256) {
        require(msg.value >= minEther, "Too small funds");
        require(_percent >= ILogic(settings.logicManager()).withdrawPercent(msg.value), "Collateralization is not enough");

        Bid memory _bid = Bid(
            tx.origin,
            msg.value,
            _percent
        );
        uint256 _id = bids.push(_bid).sub(1);
        emit BidCreated(_id, tx.origin, msg.value, _percent);
        return _id;
    }


    function close(uint256 _id) external onlyOwner(_id) {
        uint256 _eth = bids[_id].pack;
        delete bids[_id];
        msg.sender.transfer(_eth);
        emit BidClosed(_id, msg.sender);
    }


    function take(uint256 _id) external payable onlyExists(_id) {

        address payable _owner = bids[_id].owner;
        uint256 _eth = bids[_id].pack.mul(divider).div(bids[_id].percent);

        require(msg.value == _eth, "Incorrect ETH value");

        uint256 _sysEth = _eth.mul(commission).div(divider);
        systemETH = systemETH.add(_sysEth);
        uint256 _tmv = _eth.mul(ILogic(settings.logicManager()).rate()).div(ILogic(settings.logicManager()).precision());
        uint256 _box = ILogic(settings.logicManager()).create.value(bids[_id].pack)(_tmv);
        uint256 _sysTmv = _tmv.mul(commission).div(divider);
        delete bids[_id];
        _owner.transfer(_eth.sub(_sysEth));
        ILogic(settings.logicManager()).transferFrom(address(this), _owner, _box);
        IToken(settings.tmvAddress()).transfer(msg.sender, _tmv.sub(_sysTmv));
        emit BidMatched(_id, _box, msg.sender, _owner);
    }
}

pragma solidity ^0.5.16;


import "./BaseSynthetix.sol";


import "./interfaces/IRewardEscrow.sol";
import "./interfaces/IRewardEscrowV2.sol";
import "./interfaces/ISupplySchedule.sol";


contract Synthetix is BaseSynthetix {

    bytes32 private constant CONTRACT_REWARD_ESCROW = "RewardEscrow";
    bytes32 private constant CONTRACT_REWARDESCROW_V2 = "RewardEscrowV2";
    bytes32 private constant CONTRACT_SUPPLYSCHEDULE = "SupplySchedule";



    constructor(
        address payable _proxy,
        TokenState _tokenState,
        address _owner,
        uint _totalSupply,
        address _resolver
    ) public BaseSynthetix(_proxy, _tokenState, _owner, _totalSupply, _resolver) {}

    function resolverAddressesRequired() public view returns (bytes32[] memory addresses) {
        bytes32[] memory existingAddresses = BaseSynthetix.resolverAddressesRequired();
        bytes32[] memory newAddresses = new bytes32[](3);
        newAddresses[0] = CONTRACT_REWARD_ESCROW;
        newAddresses[1] = CONTRACT_REWARDESCROW_V2;
        newAddresses[2] = CONTRACT_SUPPLYSCHEDULE;
        return combineArrays(existingAddresses, newAddresses);
    }



    function rewardEscrow() internal view returns (IRewardEscrow) {
        return IRewardEscrow(requireAndGetAddress(CONTRACT_REWARD_ESCROW));
    }

    function rewardEscrowV2() internal view returns (IRewardEscrowV2) {
        return IRewardEscrowV2(requireAndGetAddress(CONTRACT_REWARDESCROW_V2));
    }

    function supplySchedule() internal view returns (ISupplySchedule) {
        return ISupplySchedule(requireAndGetAddress(CONTRACT_SUPPLYSCHEDULE));
    }



    function exchangeWithVirtual(
        bytes32 sourceCurrencyKey,
        uint sourceAmount,
        bytes32 destinationCurrencyKey,
        bytes32 trackingCode
    )
        external
        exchangeActive(sourceCurrencyKey, destinationCurrencyKey)
        optionalProxy
        returns (uint amountReceived, IVirtualSynth vSynth)
    {
        return
            exchanger().exchange(
                messageSender,
                messageSender,
                sourceCurrencyKey,
                sourceAmount,
                destinationCurrencyKey,
                messageSender,
                true,
                messageSender,
                trackingCode
            );
    }




    function exchangeWithTrackingForInitiator(
        bytes32 sourceCurrencyKey,
        uint sourceAmount,
        bytes32 destinationCurrencyKey,
        address rewardAddress,
        bytes32 trackingCode
    ) external exchangeActive(sourceCurrencyKey, destinationCurrencyKey) optionalProxy returns (uint amountReceived) {

        (amountReceived, ) = exchanger().exchange(
            messageSender,
            messageSender,
            sourceCurrencyKey,
            sourceAmount,
            destinationCurrencyKey,

            tx.origin,
            false,
            rewardAddress,
            trackingCode
        );
    }

    function settle(bytes32 currencyKey)
        external
        optionalProxy
        returns (
            uint reclaimed,
            uint refunded,
            uint numEntriesSettled
        )
    {
        return exchanger().settle(messageSender, currencyKey);
    }

    function mint() external issuanceActive returns (bool) {
        require(address(rewardsDistribution()) != address(0), "RewardsDistribution not set");

        ISupplySchedule _supplySchedule = supplySchedule();
        IRewardsDistribution _rewardsDistribution = rewardsDistribution();

        uint supplyToMint = _supplySchedule.mintableSupply();
        require(supplyToMint > 0, "No supply is mintable");


        _supplySchedule.recordMintEvent(supplyToMint);



        uint minterReward = _supplySchedule.minterReward();

        uint amountToDistribute = supplyToMint.sub(minterReward);


        tokenState.setBalanceOf(
            address(_rewardsDistribution),
            tokenState.balanceOf(address(_rewardsDistribution)).add(amountToDistribute)
        );
        emitTransfer(address(this), address(_rewardsDistribution), amountToDistribute);


        _rewardsDistribution.distributeRewards(amountToDistribute);


        tokenState.setBalanceOf(msg.sender, tokenState.balanceOf(msg.sender).add(minterReward));
        emitTransfer(address(this), msg.sender, minterReward);

        totalSupply = totalSupply.add(supplyToMint);

        return true;
    }

    function liquidateDelinquentAccount(address account, uint susdAmount)
        external
        systemActive
        optionalProxy
        returns (bool)
    {
        (uint totalRedeemed, uint amountLiquidated) =
            issuer().liquidateDelinquentAccount(account, susdAmount, messageSender);

        emitAccountLiquidated(account, totalRedeemed, amountLiquidated, messageSender);



        return _transferByProxy(account, messageSender, totalRedeemed);
    }


    function migrateEscrowBalanceToRewardEscrowV2() external onlyOwner {

        uint rewardEscrowBalance = tokenState.balanceOf(address(rewardEscrow()));



        _internalTransfer(address(rewardEscrow()), address(rewardEscrowV2()), rewardEscrowBalance);
    }


    event AccountLiquidated(address indexed account, uint snxRedeemed, uint amountLiquidated, address liquidator);
    bytes32 internal constant ACCOUNTLIQUIDATED_SIG = keccak256("AccountLiquidated(address,uint256,uint256,address)");

    function emitAccountLiquidated(
        address account,
        uint256 snxRedeemed,
        uint256 amountLiquidated,
        address liquidator
    ) internal {
        proxy._emit(
            abi.encode(snxRedeemed, amountLiquidated, liquidator),
            2,
            ACCOUNTLIQUIDATED_SIG,
            addressToBytes32(account),
            0,
            0
        );
    }
}

pragma solidity ^0.4.24;

import './LighthouseAPI.sol';
import './LighthouseABI.sol';
import './LiabilityFactory.sol';

contract LighthouseLib is LighthouseAPI, LighthouseABI {

    function refill(uint256 _value) external {
        require(xrt.transferFrom(msg.sender, this, _value));
        require(_value >= minimalFreeze);

        if (balances[msg.sender] == 0) {
            indexOf[msg.sender] = members.length;
            members.push(msg.sender);
        }
        balances[msg.sender] += _value;
    }

    function withdraw(uint256 _value) external {
        require(balances[msg.sender] >= _value);

        require(xrt.transfer(msg.sender, _value));
        balances[msg.sender] -= _value;


        if (quotaOf(msg.sender) == 0) {
            require(xrt.transfer(msg.sender, balances[msg.sender])); 
            balances[msg.sender] = 0;

            uint256 senderIndex = indexOf[msg.sender];
            uint256 lastIndex = members.length - 1;
            if (senderIndex < lastIndex)
                members[senderIndex] = members[lastIndex];
            members.length -= 1;
        }
    }

    function nextMember() internal
    { marker = (marker + 1) % members.length; }

    modifier quoted {
        if (quota == 0) {

            nextMember();


            quota = quotaOf(members[marker]);
        }



        quota -= 1;

        _;
    }

    modifier keepalive {
        if (timeoutBlocks < block.number - keepaliveBlock) {

            while (msg.sender != members[marker])
                nextMember();


            quota = quotaOf(members[marker]);
        }

        _;
    }

    modifier member {

        require(members.length > 0);


        require(msg.sender == members[marker]);


        keepaliveBlock = block.number;

        _;
    }

    function to(address _to, bytes _data) external keepalive quoted member
    { require(_to.call(_data)); }

    function () external keepalive quoted member
    { require(factory.call(msg.data)); }
}

pragma solidity 0.6.10;

pragma experimental ABIEncoderV2;

import {CalleeInterface} from "../../interfaces/CalleeInterface.sol";
import {ZeroXExchangeInterface} from "../../interfaces/ZeroXExchangeInterface.sol";
import {ERC20Interface} from "../../interfaces/ERC20Interface.sol";
import {WETH9Interface} from "../../interfaces/WETH9Interface.sol";

import {SafeERC20} from "../../packages/oz/SafeERC20.sol";


contract TradeCallee is CalleeInterface {
    using SafeERC20 for ERC20Interface;


    uint256 private PROTOCOL_FEE_BASE = 70000;

    ZeroXExchangeInterface public exchange;
    WETH9Interface public weth;

    address public controller;

    constructor(
        address _exchange,
        address _weth,
        address _controller
    ) public {
        exchange = ZeroXExchangeInterface(_exchange);
        weth = WETH9Interface(_weth);
        controller = _controller;
    }


    function callFunction(address payable _sender, bytes memory _data) external override {
        require(msg.sender == controller, "TradeCallee: sender is not controller");

        (
            address trader,
            ZeroXExchangeInterface.LimitOrder[] memory orders,
            ZeroXExchangeInterface.Signature[] memory signatures,
            uint128[] memory takerTokenFillAmounts,
            bool revertIfIncomplete
        ) = abi.decode(
            _data,
            (address, ZeroXExchangeInterface.LimitOrder[], ZeroXExchangeInterface.Signature[], uint128[], bool)
        );




        require(
            tx.origin == trader,
            "TradeCallee: funds can only be transferred in from the person sending the transaction"
        );

        for (uint256 i = 0; i < orders.length; i++) {
            address takerAsset = orders[i].takerToken;

            ERC20Interface(takerAsset).safeTransferFrom(trader, address(this), takerTokenFillAmounts[i]);

            ERC20Interface(takerAsset).safeIncreaseAllowance(address(exchange), takerTokenFillAmounts[i]);
        }


        uint256 protocolFee = tx.gasprice * PROTOCOL_FEE_BASE * orders.length;
        weth.transferFrom(_sender, address(this), protocolFee);
        weth.withdraw(protocolFee); 


        exchange.batchFillLimitOrders{value: protocolFee}(
            orders,
            signatures,
            takerTokenFillAmounts,
            revertIfIncomplete
        );

        for (uint256 i = 0; i < orders.length; i++) {

            address asset = orders[i].makerToken;

            uint256 balance = ERC20Interface(asset).balanceOf(address(this));
            if (balance > 0) {
                ERC20Interface(asset).safeTransfer(trader, balance);
            }


            asset = orders[i].takerToken;

            balance = ERC20Interface(asset).balanceOf(address(this));
            if (balance > 0) {
                ERC20Interface(asset).safeTransfer(trader, balance);
            }
        }
    }


    fallback() external payable {}
}

pragma solidity 0.7.6;



import "../interface/RocketStorageInterface.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";




contract RocketStorage is RocketStorageInterface {


    event NodeWithdrawalAddressSet(address indexed node, address indexed withdrawalAddress, uint256 time);
    event GuardianChanged(address oldGuardian, address newGuardian);


    using SafeMath for uint256;


    mapping(bytes32 => string)     private stringStorage;
    mapping(bytes32 => bytes)      private bytesStorage;


    mapping(address => address)    private withdrawalAddresses;
    mapping(address => address)    private pendingWithdrawalAddresses;


    address guardian;
    address newGuardian;


    bool storageInit = false;


    modifier onlyLatestRocketNetworkContract() {
        if (storageInit == true) {

            require(_getBool(keccak256(abi.encodePacked("contract.exists", msg.sender))), "Invalid or outdated network contract");
        } else {



            require((
                _getBool(keccak256(abi.encodePacked("contract.exists", msg.sender))) || tx.origin == guardian
            ), "Invalid or outdated network contract attempting access during deployment");
        }
        _;
    }



    constructor() {

        guardian = msg.sender;
    }


    function getGuardian() external override view returns (address) {
        return guardian;
    }


    function setGuardian(address _newAddress) external override {

        require(msg.sender == guardian, "Is not guardian account");

        newGuardian = _newAddress;
    }


    function confirmGuardian() external override {

        require(msg.sender == newGuardian, "Confirmation must come from new guardian address");

        address oldGuardian = guardian;

        guardian = newGuardian;
        delete newGuardian;

        emit GuardianChanged(oldGuardian, guardian);
    }


    function getDeployedStatus() external view returns (bool) {
        return storageInit;
    }


    function setDeployedStatus() external {

        require(msg.sender == guardian, "Is not guardian account");

        storageInit = true;
    }




    function getNodeWithdrawalAddress(address _nodeAddress) public override view returns (address) {

        if (!_getBool(keccak256(abi.encodePacked("node.exists", _nodeAddress)))) {
            return address(0);
        }

        address withdrawalAddress = withdrawalAddresses[_nodeAddress];
        if (withdrawalAddress == address(0)) {
            return _nodeAddress;
        }
        return withdrawalAddress;
    }


    function getNodePendingWithdrawalAddress(address _nodeAddress) external override view returns (address) {
        return pendingWithdrawalAddresses[_nodeAddress];
    }


    function setWithdrawalAddress(address _nodeAddress, address _newWithdrawalAddress, bool _confirm) external override {

        require(_newWithdrawalAddress != address(0x0), "Invalid withdrawal address");

        address withdrawalAddress = getNodeWithdrawalAddress(_nodeAddress);
        require(withdrawalAddress == msg.sender, "Only a tx from a node's withdrawal address can update it");

        if (_confirm) {
            updateWithdrawalAddress(_nodeAddress, _newWithdrawalAddress);
        }

        else {
            pendingWithdrawalAddresses[_nodeAddress] = _newWithdrawalAddress;
        }
    }


    function confirmWithdrawalAddress(address _nodeAddress) external override {

        require(pendingWithdrawalAddresses[_nodeAddress] == msg.sender, "Confirmation must come from the pending withdrawal address");
        delete pendingWithdrawalAddresses[_nodeAddress];

        updateWithdrawalAddress(_nodeAddress, msg.sender);
    }


    function updateWithdrawalAddress(address _nodeAddress, address _newWithdrawalAddress) private {

        withdrawalAddresses[_nodeAddress] = _newWithdrawalAddress;

        emit NodeWithdrawalAddressSet(_nodeAddress, _newWithdrawalAddress, block.timestamp);
    }


    function getAddress(bytes32 _key) override external view returns (address r) {
        assembly {
            r := sload (_key)
        }
    }


    function getUint(bytes32 _key) override external view returns (uint256 r) {
        assembly {
            r := sload (_key)
        }
    }


    function getString(bytes32 _key) override external view returns (string memory) {
        return stringStorage[_key];
    }


    function getBytes(bytes32 _key) override external view returns (bytes memory) {
        return bytesStorage[_key];
    }


    function getBool(bytes32 _key) override external view returns (bool r) {
        assembly {
            r := sload (_key)
        }
    }


    function getInt(bytes32 _key) override external view returns (int r) {
        assembly {
            r := sload (_key)
        }
    }


    function getBytes32(bytes32 _key) override external view returns (bytes32 r) {
        assembly {
            r := sload (_key)
        }
    }



    function setAddress(bytes32 _key, address _value) onlyLatestRocketNetworkContract override external {
        assembly {
            sstore (_key, _value)
        }
    }



    function setUint(bytes32 _key, uint _value) onlyLatestRocketNetworkContract override external {
        assembly {
            sstore (_key, _value)
        }
    }


    function setString(bytes32 _key, string calldata _value) onlyLatestRocketNetworkContract override external {
        stringStorage[_key] = _value;
    }


    function setBytes(bytes32 _key, bytes calldata _value) onlyLatestRocketNetworkContract override external {
        bytesStorage[_key] = _value;
    }


    function setBool(bytes32 _key, bool _value) onlyLatestRocketNetworkContract override external {
        assembly {
            sstore (_key, _value)
        }
    }



    function setInt(bytes32 _key, int _value) onlyLatestRocketNetworkContract override external {
        assembly {
            sstore (_key, _value)
        }
    }


    function setBytes32(bytes32 _key, bytes32 _value) onlyLatestRocketNetworkContract override external {
        assembly {
            sstore (_key, _value)
        }
    }



    function deleteAddress(bytes32 _key) onlyLatestRocketNetworkContract override external {
        assembly {
            sstore (_key, 0)
        }
    }


    function deleteUint(bytes32 _key) onlyLatestRocketNetworkContract override external {
        assembly {
            sstore (_key, 0)
        }
    }


    function deleteString(bytes32 _key) onlyLatestRocketNetworkContract override external {
        delete stringStorage[_key];
    }


    function deleteBytes(bytes32 _key) onlyLatestRocketNetworkContract override external {
        delete bytesStorage[_key];
    }


    function deleteBool(bytes32 _key) onlyLatestRocketNetworkContract override external {
        assembly {
            sstore (_key, 0)
        }
    }


    function deleteInt(bytes32 _key) onlyLatestRocketNetworkContract override external {
        assembly {
            sstore (_key, 0)
        }
    }


    function deleteBytes32(bytes32 _key) onlyLatestRocketNetworkContract override external {
        assembly {
            sstore (_key, 0)
        }
    }




    function addUint(bytes32 _key, uint256 _amount) onlyLatestRocketNetworkContract override external {
        uint256 a;
        uint256 b;
        assembly {
            a := sload (_key)
            b := add(a, _amount)
            sstore (_key, b)
        }
        require(b >= a, "SafeMath: addition overflow");
    }



    function subUint(bytes32 _key, uint256 _amount) onlyLatestRocketNetworkContract override external {
        uint256 a;
        assembly {
            a := sload (_key)
        }
        require(_amount <= a, "SafeMath: subtraction overflow");
        assembly {
            a := sub(a, _amount)
            sstore (_key, a)
        }
    }



    function _getBool(bytes32 _key) private view returns (bool r) {
        assembly {
            r := sload (_key)
        }
    }

    function _setBool(bytes32 _key, bool _value) private {
        assembly {
            sstore (_key, _value)
        }
    }
}
